class OrderManager:
    def __init__(self):
        self.orders = []
        self.exporter = OrderExporter()

    def add_order(self, order):
        self.orders.append(order)

    def calculate_total(self):
        return sum(order.total for order in self.orders)

    def export_csv(self):
        return self.exporter.export_csv(self.orders)


class OrderExporter:
    def export_csv(self, orders):
        return '\n'.join(str(order.total) for order in orders)
